# testing/traceability.py — generate BDD ↔ eval traceability report
import json
import re
from pathlib import Path
import yaml

def extract_scenario_eval_links(feature_dir: str) -> dict[str, list[str]]:
    """
    Parse feature files and extract @eval:ID tags per scenario.
    Returns {scenario_name: [eval_id, ...]}
    """
    links: dict[str, list[str]] = {}
    for feature_path in Path(feature_dir).rglob("*.feature"):
        content = feature_path.read_text()
        scenarios = re.split(r"(?=\s+Scenario:)", content)
        for block in scenarios:
            eval_tags = re.findall(r"@eval:(\S+)", block)
            name_match = re.search(r"Scenario:\s+(.+)", block)
            if name_match and eval_tags:
                name = name_match.group(1).strip()
                links[name] = eval_tags
    return links

def find_uncovered_scenarios(
    feature_dir: str,
    eval_dir: str,
) -> list[str]:
    """Find BDD scenarios that have no linked eval cases."""
    links = extract_scenario_eval_links(feature_dir)
    covered = set()
    for eval_path in Path(eval_dir).rglob("*.yaml"):
        data = yaml.safe_load(eval_path.read_text())
        if "bdd_scenario" in data:
            covered.add(data["bdd_scenario"])
    uncovered = [name for name in links if name not in covered]
    return uncovered

def coverage_report(feature_dir: str, eval_dir: str) -> str:
    links = extract_scenario_eval_links(feature_dir)
    uncovered = find_uncovered_scenarios(feature_dir, eval_dir)
    lines = [
        "# BDD ↔ Eval Traceability Report",
        f"Scenarios with eval coverage: {len(links) - len(uncovered)}/{len(links)}",
        "",
    ]
    if uncovered:
        lines += ["## Scenarios missing eval coverage:", *[f"  - {s}" for s in uncovered]]
    return "\n".join(lines)
